            <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-1 font-mono text-[8px] font-bold text-stone-400 bg-stone-100 border border-stone-200/50 px-1.5 py-0.5 rounded shadow-sm">
