        </header>

        {/* Tab Viewport */}
        <div className="flex-1 overflow-y-auto p-8 scroll-mt-20">

          {/* Tab 1: Vault Inbox list */}
          {activeTab === "vault" && (
            <div className="max-w-5xl mx-auto flex flex-col gap-6 animate-fade-in">
