                          newTag === tag
                            ? "bg-stone-900 border-stone-900 text-white"
                            : "bg-stone-50 hover:bg-stone-100 border-stone-200 text-stone-500"
                        }`}
                      >
                        #{tag}
                      </button>
                    ))}
